+    let fixture: serde_json::Value =
+        serde_json::from_slice(&fs::read(&path).expect("read fixture"))
+            .expect("parse fixture JSON");
+    let obj = fixture.as_object().expect("fixture must be object");
+    for key in [
+        "release_candidate_id",
+        "continuous_run",
